+  int get_total_binds() const { return idx_ - 1; }
+};
+
+namespace detail
+{
+template <typename R, typename T>
+R NullValueGet(T)
+{
+  throw boost::bad_get();
+}
+template <typename R>
+typename std::enable_if<!std::is_same<R, std::nullptr_t>::value, R>::type NullValueGet(R r)
+{
+  return std::forward<R>(r);
+}
+template <typename R>
+R NullValueGet(std::nullptr_t)
+{
+  return R();
