+bool warehouse_ros_sqlite::DatabaseConnection::connect()
+{
+  sqlite3* s = nullptr;
+  if (sqlite3_open(uri_.c_str(), &s) != SQLITE_OK)
+  {
+    return false;
+  }
+  db_.reset(s, warehouse_ros_sqlite::sqlite3_delete);
+  return true;
