+template <typename R>
+R warehouse_ros_sqlite::Metadata::doLookup(const std::string& name) const
+{
+  const auto res = data_.find(name);
+  if (res == data_.end())
+  {
+    throw std::range_error("");
+  }
+  return boost::apply_visitor(warehouse_ros_sqlite::NullValueVisitor<R>(), res->second);
+}
