+bool warehouse_ros_sqlite::ResultIteratorHelper::next()
+{
+  switch (sqlite3_step(stmt_.get()))
+  {
+    case SQLITE_ROW:
+
+      return true;
+    case SQLITE_DONE:
+      stmt_.reset();
+      return false;
+    default:
+      throw std::runtime_error("sqlite3_step()");
+  }
+}
+bool warehouse_ros_sqlite::ResultIteratorHelper::hasData() const
+{
+  if (!stmt_)
+    return false;
+  switch (sqlite3_column_type(stmt_.get(), schema::DataColumnIndex))
+  {
+    case SQLITE_BLOB:
+      return sqlite3_column_bytes(stmt_.get(), schema::DataColumnIndex) != 0;
+    case SQLITE_NULL:
+      return false;
+    default:
+      throw std::runtime_error("Data Column has wrong data type");
+  }
+}
+
+warehouse_ros::Metadata::ConstPtr warehouse_ros_sqlite::ResultIteratorHelper::metadata() const
+{
+  assert(static_cast<bool>(stmt_));
+  auto ans = boost::make_shared<warehouse_ros_sqlite::Metadata>();
+  for (const auto& col_pair : metadata_cols_)
+  {
+    ans->append(std::get<0>(col_pair), stmt_.get(), std::get<1>(col_pair));
+  }
+  return ans;
+}
+
+std::string warehouse_ros_sqlite::ResultIteratorHelper::message() const
+{
+  if (!hasData())
+    return std::string();
+  return std::string(reinterpret_cast<const char*>(sqlite3_column_blob(stmt_.get(), schema::DataColumnIndex)),
+                     sqlite3_column_bytes(stmt_.get(), schema::DataColumnIndex));
+}
+
+namespace
+{
+int constexpr strlength(const char* str)
+{
+  return *str ? 1 + strlength(str + 1) : 0;
+}
+}  // namespace
+
+void warehouse_ros_sqlite::ResultIteratorHelper::init_metadata_cols()
+{
+  constexpr int max_length = strlength(schema::MetadataColumnPrefix);
+  for (int i = 0; i < sqlite3_column_count(stmt_.get()); ++i)
+  {
+    const char* col_name = sqlite3_column_name(stmt_.get(), i);
+    if (std::strncmp(schema::MetadataColumnPrefix, col_name, max_length) == 0)
+    {
+      metadata_cols_.emplace_back(col_name, i);
+    }
+  }
+}

